1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUE: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const CURSE_SURCHARGE = 0.5;
23	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_DISCOUNT = 0.2;
26	const LOYALTY_THRESHOLD_YEARS = 2;
27	const FOLLOW_UP_DISCOUNT = 0.15;
28	const DEDUCTIBLE = 100;
29	const CAP_MULTIPLIER = 2;
30	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
31	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
32	
33	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
34	type Damage = { itemType: string; amount: number };
35	type Incident = { cause: string; damages: Damage[] };
36	type QuoteStep = { op: "quote"; items: Item[] };
37	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
38	type Step = QuoteStep | ClaimStep;
39	type Customer = { yearsWithMHPCO: number };
40	type Scenario = { customer: Customer; steps: Step[] };
41	type QuoteResult = { premium: number };
42	type ClaimResult = { payout: number; remainingCap: number };
43	type StepResult = QuoteResult | ClaimResult;
44	
45	// MHPCO rounds premiums up in its own favor. A float-precision guard avoids
46	// surprises like 197.5 + 0 rendering as 197.5000000001 and rounding to 198
47	// when the true mathematical value was already on an integer boundary.
48	const roundUpInMHPCOFavor = (amount: number): number =>
49	  Math.ceil(Math.round(amount * 1e6) / 1e6);
50	
51	const roundDownInMHPCOFavor = (amount: number): number =>
52	  Math.floor(Math.round(amount * 1e6) / 1e6);
53	
54	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
55	const COMPONENT_BLOCK_SIZE = 3;
56	const COMPONENT_BLOCK_PREMIUM = 60;
57	
58	const componentGroupPremium = (type: string, count: number): number =>
59	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * BASE_PREMIUM[type];
60	
61	type PremiumLine = { base: number; itemSurchargeRate: number };
62	
63	const mainItemSurchargeRate = (item: Item): number => {
64	  let rate = 0;
65	  if (item.cursed) rate += CURSE_SURCHARGE;
66	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE;
67	  return rate;
68	};
69	
70	const mainItemLine = (item: Item): PremiumLine => {
71	  const base = BASE_PREMIUM[item.type];
72	  if (base === undefined) {
73	    throw new Error(`Unknown item type: ${item.type}`);
74	  }
75	  return { base, itemSurchargeRate: mainItemSurchargeRate(item) };
76	};
77	
78	const itemPremiumLines = (items: Item[]): PremiumLine[] => {
79	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
80	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
81	  const componentCountsByType = new Map<string, number>();
82	  for (const c of components) {
83	    componentCountsByType.set(c.type, (componentCountsByType.get(c.type) ?? 0) + 1);
84	  }
85	  const mainLines = mainItems.map(mainItemLine);
86	  const componentLines = [...componentCountsByType].map(([type, count]) => ({
87	    base: componentGroupPremium(type, count),
88	    itemSurchargeRate: 0,
89	  }));
90	  return [...mainLines, ...componentLines];
91	};
92	
93	const linePremium = (line: PremiumLine): number =>
94	  line.base * (1 + FIRST_INSURANCE_SURCHARGE + line.itemSurchargeRate);
95	
96	const policyWideRate = (customer: Customer, quoteIndex: number): number => {
97	  let rate = 0;
98	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
99	  if (quoteIndex > 0) rate -= FOLLOW_UP_DISCOUNT;
100	  return rate;
101	};
102	
103	const computePremium = (step: QuoteStep, customer: Customer, quoteIndex: number): number => {
104	  const lines = itemPremiumLines(step.items);
105	  const itemSurchargeTotal = lines.map(linePremium).reduce((sum, p) => sum + p, 0);
106	  const policyBase = lines.reduce((sum, l) => sum + l.base, 0);
107	  const total = itemSurchargeTotal + policyBase * policyWideRate(customer, quoteIndex) + PROCESSING_FEE;
108	  return roundUpInMHPCOFavor(total);
109	};
110	
111	type Policy = { items: Item[]; cap: number };
112	
113	const createPolicy = (items: Item[]): Policy => {
114	  const insuranceSum = items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
115	  return { items, cap: insuranceSum * CAP_MULTIPLIER };
116	};
117	
118	const damagePayout = (damage: Damage, item: Item): number => {
119	  const reimbursementRate = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
120	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
121	    : 1;
122	  return Math.max(0, damage.amount * reimbursementRate - DEDUCTIBLE);
123	};
124	
125	const countByType = <T extends { type?: string; itemType?: string }>(items: T[], key: "type" | "itemType"): Map<string, number> => {
126	  const counts = new Map<string, number>();
127	  for (const item of items) {
128	    const t = item[key]!;
129	    counts.set(t, (counts.get(t) ?? 0) + 1);
130	  }
131	  return counts;
132	};
133	
134	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
135	  const policy = policies[step.policy];
136	  const policyCounts = countByType(policy.items, "type");
137	  const damageCounts = countByType(step.incident.damages, "itemType");
138	  for (const [type, count] of damageCounts) {
139	    if (count > (policyCounts.get(type) ?? 0)) {
140	      throw new Error(`Claim has more ${type} damages than insured`);
141	    }
142	  }
143	  const totalDamage = step.incident.damages.reduce((sum, d) => {
144	    const item = policy.items.find((i) => i.type === d.itemType)!;
145	    return sum + damagePayout(d, item);
146	  }, 0);
147	  const payout = roundDownInMHPCOFavor(totalDamage);
148	  policy.cap -= payout;
149	  return { payout, remainingCap: policy.cap };
150	};
151	
152	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
153	  const policies: Policy[] = [];
154	  const results: StepResult[] = scenario.steps.map((step) => {
155	    if (step.op === "quote") {
156	      const premium = computePremium(step, scenario.customer, policies.length);
157	      policies.push(createPolicy(step.items));
158	      return { premium };
159	    }
160	    return processClaim(step, policies);
161	  });
162	  return { results };
163	};
